import React, { useEffect, useState } from 'react';
import axios from 'axios';

const EmpresasPanel = () => {
  const [empresas, setEmpresas] = useState([]);
  const [imagenLateral, setImagenLateral] = useState('');
  const [ordenAntigüedad, setOrdenAntigüedad] = useState('desc'); // 'asc' o 'desc'
  const [selectedEmpresa, setSelectedEmpresa] = useState(null);
  const [showModal, setShowModal] = useState(false);

  useEffect(() => {
    axios.get('http://localhost:3000/empresas')
      .then(res => setEmpresas(res.data))
      .catch(err => console.error('Error al obtener empresas:', err));
  }, []);

  return (
    <div className="min-h-screen w-full bg-[#0000] p-3 sm:p-10 md:p-10 flex flex-col items-center">

      <div className="bg-[#202020] w-full max-w-6xl rounded-lg shadow-lg overflow-hidden">
        <div className="bg-[#2b2b2b] px-3 sm:px-4 md:px-7 py-2 sm:py-3 md:py-4 flex flex-col sm:flex-row justify-between items-center gap-2 sm:gap-3 md:gap-4">
          <span className="text-[#F9F9FA] text-base sm:text-lg w-full sm:w-auto text-center sm:text-left mb-2 sm:mb-0">DATOS</span>
          <div className="flex flex-col sm:flex-row items-center justify-center gap-5 sm:gap-30 w-full">
            <img src="/icons/filtro.png" alt="Filtro" className="w-4 h-4 sm:w-5 sm:h-5 hidden sm:block" />
            <div className="relative w-full max-w-md">
              <input
                type="text"
                placeholder="Buscar..."
                className="rounded-full px-3 py-1 pl-8 sm:pl-10 w-full bg-[#FCFCFD] text-black focus:outline-none text-sm sm:text-base"
              />
              <img 
                src="/icons/lupa.png" 
                alt="Buscar" 
                className="absolute left-2 sm:left-3 top-1/2 -translate-y-1/2 w-3 h-3 sm:w-4 sm:h-4" 
              />
            </div>
            <div className="flex gap-3 sm:gap-4 items-center mt-2 sm:mt-0">
              <img src="/icons/medalla.png" alt="Medalla" className="w-4 h-4 sm:w-5 sm:h-5" />
              <div className="flex items-center">
                <img src="/icons/plus.png" alt="Plus" className="w-3 h-3 sm:w-4 sm:h-4 mr-1" />
                <span className="text-[#e1e4c5] text-sm sm:text-base">50</span>
              </div>
              <img src="/icons/cerebro.png" alt="Cerebro" className="w-4 h-4 sm:w-5 sm:h-5" />
              <img src="/icons/mapa.png" alt="Mapa" className="w-4 h-4 sm:w-5 sm:h-5" />
            </div>
          </div>
        </div>

        <div className="grid grid-cols-1 xs:grid-cols-2 md:grid-cols-3 lg:grid-cols-4 gap-3 sm:gap-4 md:gap-6 px-3 sm:px-4 md:px-6 py-3 sm:py-4 md:py-6">
  {empresas.map((empresa, index) => (
    <div
      key={empresa.id_empresa || index}
      className="bg-white rounded-lg sm:rounded-xl p-3 sm:p-4 text-black shadow-md flex flex-col justify-center items-start"
    >
      <span className="text-[#2b2b2b] font-bold text-lg sm:text-xl">
        {empresa.denominacion_social || 'Sin nombre comercial'}
      </span>
      <span className="text-gray-600 text-sm sm:text-base mt-1">
        {empresa.id_empresa || 'Sin razón social'}
      </span>
    </div>
  ))}
</div>



      </div>
    </div>
  );
};

export default EmpresasPanel;
